SELECT w.*, lib.widget_nm AS widget_lib_nm, ste.site_nm AS site_nm, cd_wt.code_label AS widget_type_cd_nm FROM dp_widget w LEFT JOIN dp_widget_lib lib ON lib.widget_lib_id = w.widget_lib_id LEFT JOIN sy_site ste ON ste.site_id = w.site_id LEFT JOIN sy_code cd_wt ON cd_wt.code_grp = 'WIDGET_TYPE' AND cd_wt.code_value = w.widget_type_cd
ORDER BY w.widget_id ASC ORDER BY w.widget_id DESC ORDER BY w.widget_nm ASC ORDER BY w.widget_nm DESC ORDER BY w.reg_date ASC ORDER BY w.reg_date DESC ORDER BY w.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

mapper.update:
UPDATE dp_widget
widget_lib_id = #{widgetLibId}, site_id = #{siteId}, widget_nm = #{widgetNm}, widget_type_cd = #{widgetTypeCd}, widget_desc = #{widgetDesc}, widget_title = #{widgetTitle}, widget_content = #{widgetContent}, title_show_yn = #{titleShowYn}, widget_lib_ref_yn = #{widgetLibRefYn}, widget_config_json = #{widgetConfigJson}, preview_img_url = #{previewImgUrl}, sort_ord = #{sortOrd}, use_yn = #{useYn}, disp_env = #{dispEnv}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE widget_id = #{widgetId}
